from flask import Flask, session, request, jsonify
import redis
import functools
import time
import hashlib

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

# Session management with Redis
@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = redis_client.get(f"session:{session_id}")
        if session_data:
            session.update(eval(session_data))

@app.after_request
def save_session(response):
    if 'user_id' in session:
        session_id = session.get('session_id')
        if not session_id:
            session_id = hashlib.md5(str(time.time()).encode()).hexdigest()
            session['session_id'] = session_id
        redis_client.setex(f"session:{session_id}", 3600, str(dict(session)))
        response.set_cookie('session_id', session_id, max_age=3600)
    return response

# Cache decorator for expensive queries
def cache_result(timeout=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return eval(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, timeout, str(result))
            return result
        return wrapper
    return decorator

# Example expensive database query function
@cache_result(timeout=600)
def expensive_database_query(user_id):
    # Simulate expensive database operation
    time.sleep(2)
    return {"user_id": user_id, "data": f"expensive_data_for_user_{user_id}"}

@app.route('/user/<int:user_id>')
def get_user_data(user_id):
    # This will be cached after first call
    data = expensive_database_query(user_id)
    return jsonify(data)

